#!/usr/bin/env bash
# Removes only artifacts generated by build.sh.
# Touches nothing inside .ai/.
set -euo pipefail

REPO_ROOT="$(cd "$(dirname "$0")/../../.." && pwd)"
DST_DIR="$REPO_ROOT/.claude/skills"

if [ -d "$DST_DIR" ]; then
  # Only remove subdirs whose SKILL.md carries our GENERATED header.
  for d in "$DST_DIR"/*/; do
    [ -d "$d" ] || continue
    f="$d/SKILL.md"
    if [ -f "$f" ] && head -n 1 "$f" | grep -q "GENERATED FROM .ai/skills/"; then
      rm -rf "$d"
      echo "  removed: ${d#$REPO_ROOT/}"
    fi
  done
  # Remove parent dir if now empty.
  rmdir "$DST_DIR" 2>/dev/null || true
fi
echo "Clean complete."
